// n8n Code node - DBH EHR Chatbot v6.2
const body = $input.item.json;
const token = (body.body && body.body.token) || body.token || '';
const rawMsg = ((body.body && body.body.message) || body.message || '').trim();
const GATEWAY = 'http://gateway:5000';
const AI_KEY = $env.OPENROUTER_API_KEY || '';

if (!token) {
  return [{ json: { type: 'text', message: '⚠️ Vui lòng đăng nhập để sử dụng tính năng này.' } }];
}

// ── Helpers ──────────────────────────────────────
async function httpGet(url) {
  return await this.helpers.httpRequest({
    method: 'GET', url,
    headers: { Authorization: 'Bearer ' + token },
    json: true
  });
}

async function httpPost(url, payload) {
  return await this.helpers.httpRequest({
    method: 'POST', url,
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: payload, json: true
  });
}

// Gọi API không throw khi 4xx — luôn đọc được body lỗi
async function httpSafe(method, url, payload) {
  try {
    return await this.helpers.httpRequest({
      method, url,
      headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
      body: payload || undefined,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
  } catch(e) {
    let errBody = null;
    try { errBody = e.response?.body || e.response?.data || null; } catch(_) {}
    return { statusCode: 400, body: errBody || { message: e.message } };
  }
}

function extractErrMsg(payload) {
  if (!payload) return 'Lỗi không xác định';
  if (typeof payload === 'string') { try { payload = JSON.parse(payload); } catch(_) { return payload; } }
  return payload.message || payload.Message || payload.title ||
         Object.values(payload.errors || {})?.[0]?.[0] || JSON.stringify(payload);
}

function fmtStatus(s) {
  const map = { PENDING:'⏳ Chờ duyệt', CONFIRMED:'✅ Đã xác nhận', CHECKED_IN:'🏥 Đã đến',
    IN_PROGRESS:'🔄 Đang khám', COMPLETED:'✔️ Hoàn thành', CANCELLED:'❌ Đã hủy',
    NO_SHOW:'⚠️ Vắng mặt', RESCHEDULED:'📅 Dời lịch' };
  return map[s] || s;
}

function fmtDateTime(iso) {
  const d = new Date(iso);
  const pad = n => String(n).padStart(2,'0');
  return pad(d.getDate()) + '/' + pad(d.getMonth()+1) + '/' + d.getFullYear() +
         ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes());
}

// ── 1. ACTION commands ──────────────────────────────────────
if (rawMsg.startsWith('ACTION:')) {
  const parts = rawMsg.split('|');
  const cmd = parts[0];

  // ── ĐẶT LỊCH: Chọn ngày ──────────────────────────────
  if (cmd.startsWith('ACTION:BOOK_DOCTOR_ID:')) {
    const doctorId = cmd.replace('ACTION:BOOK_DOCTOR_ID:', '');
    const orgId = (parts[1] || '').replace('ORG:', '');
    const dates = [];
    const today = new Date();
    for (let i = 1; i <= 6; i++) {
      const d = new Date(today); d.setDate(today.getDate() + i);
      const label = d.toLocaleDateString('vi-VN', { weekday: 'short', day: '2-digit', month: '2-digit' });
      const yy = d.getFullYear(), mm = String(d.getMonth()+1).padStart(2,'0'), dd = String(d.getDate()).padStart(2,'0');
      const value = yy + '-' + mm + '-' + dd;
      dates.push({ id: value, label, sublabel: value, payload: 'ACTION:SELECT_DATE:' + value + '|DOC:' + doctorId + '|ORG:' + orgId });
    }
    return [{ json: { type: 'date_selection', message: 'Chọn ngày khám:', data: dates } }];
  }

  // ── ĐẶT LỊCH: Chọn giờ ────────────────────────~~~~
  if (cmd.startsWith('ACTION:SELECT_DATE:')) {
    const date = cmd.replace('ACTION:SELECT_DATE:', '');
    const doctorId = (parts[1] || '').replace('DOC:', '');
    const orgId = (parts[2] || '').replace('ORG:', '');
    const slots = ['08:00','08:30','09:00','09:30','10:00','14:00','14:30','15:00','15:30','16:00'];
    const timeData = slots.map(s => ({ id: s, label: s,
      payload: 'ACTION:PREVIEW_BOOKING:' + date + 'T' + s + ':00|DOC:' + doctorId + '|ORG:' + orgId }));
    return [{ json: { type: 'time_selection', message: 'Ngày ' + date + ' — Chọn giờ :', data: timeData } }];
  }

  // ── ĐẶT LỊCH: Preview xác nhận ──────────────────────────────
  if (cmd.startsWith('ACTION:PREVIEW_BOOKING:')) {
    const scheduledRaw = cmd.replace('ACTION:PREVIEW_BOOKING:', '');
    const doctorId = (parts[1] || '').replace('DOC:', '');
    const orgId = (parts[2] || '').replace('ORG:', '');
    const datePart = scheduledRaw.split('T')[0];
    const timePart = scheduledRaw.split('T')[1]?.substring(0, 5);
    const previewData = [
      { id: 'confirm', label: '✅ Đồng ý', payload: 'ACTION:EXECUTE_BOOKING:' + scheduledRaw + '|DOC:' + doctorId + '|ORG:' + orgId },
      { id: 'cancel', label: '❌ Hủy bỏ', payload: 'Hủy đặt lịch' }
    ];
    return [{ json: { type: 'date_selection',
      message: '🔍 XÁC NHẬN:\n📅 Ngày: ' + datePart + '\n⏰ Giờ : ' + timePart + '\nBạn xác nhận đặt lịch?',
      data: previewData } }];
  }

  // ── ĐẶT LỊCH: Thực thi ──────────────────────────────
  if (cmd.startsWith('ACTION:EXECUTE_BOOKING:')) {
    const scheduledRaw = cmd.replace('ACTION:EXECUTE_BOOKING:', '');
    const dateTime = scheduledRaw.includes('T') ? (scheduledRaw.length === 16 ? scheduledRaw + ':00' : scheduledRaw) : scheduledRaw;
    const doctorId = (parts[1] || '').replace('DOC:', '');
    const orgId = (parts[2] || '').replace('ORG:', '');

    let patientId = '';
    try {
      const pd = await httpGet(GATEWAY + '/api/v1/auth/me');
      const p = pd.profiles || pd.Profiles || {};
      const pt = p.Patient || p.patient || {};
      patientId = pt.patientId || pt.PatientId || '';
    } catch(e) { return [{ json: { type: 'text', message: '❌ Lỗi lấy hồ sơ: ' + e.message } }]; }

    if (!patientId) return [{ json: { type: 'text', message: '⚠️ Tài khoản chưa có hồ sơ Bệnh nhân.' } }];

    const res = await httpSafe('POST', GATEWAY + '/api/v1/Appointments', { patientId, doctorId, orgId, scheduledAt: dateTime });
    if (res.statusCode === 200 || res.statusCode === 201) {
      return [{ json: { type: 'text', message: '✅ Lịch khám đã được đặt thành công!' } }];
    } else {
      return [{ json: { type: 'text', message: '❌ ' + extractErrMsg(res.body) } }];
    }
  }

  // ── XEM LỊCH: Hiển thị danh sách ────────────────────────~~~~~~
  if (cmd === 'ACTION:VIEW_APPOINTMENTS') {
    let patientId = '';
    try {
      const pd = await httpGet(GATEWAY + '/api/v1/auth/me');
      const p = pd.profiles || pd.Profiles || {};
      const pt = p.Patient || p.patient || {};
      patientId = pt.patientId || pt.PatientId || '';
    } catch(e) { return [{ json: { type: 'text', message: '❌ Lỗi lấy hồ sơ: ' + e.message } }]; }

    if (!patientId) return [{ json: { type: 'text', message: '⚠️ Tài khoản chưa có hồ sơ Bệnh nhân.' } }];

    const res = await httpSafe('GET', GATEWAY + '/api/v1/Appointments?patientId=' + patientId + '&page=1&pageSize=8');
    if (res.statusCode !== 200) return [{ json: { type: 'text', message: '❌ ' + extractErrMsg(res.body) } }];

    const appts = (res.body.data || res.body.Data || []).filter(a => a.status !== 'CANCELLED' && a.status !== 'COMPLETED');
    if (appts.length === 0) return [{ json: { type: 'text', message: '📅 Bạn không có lịch hẹn nào đang hoạt động.' } }];

    const items = appts.map(a => ({
      id: a.appointmentId,
      label: fmtDateTime(a.scheduledAt),
      sublabel: fmtStatus(a.status),
      payload: 'ACTION:APPT_DETAIL:' + a.appointmentId
    }));
    return [{ json: { type: 'date_selection', message: '📋 Lịch hẹn của bạn (chọn để xem chi tiết):', data: items } }];
  }

  // ── XEM LỊCH: Chi tiết 1 lịch hẹn ────────────────────────~~~~
  if (cmd.startsWith('ACTION:APPT_DETAIL:')) {
    const apptId = cmd.replace('ACTION:APPT_DETAIL:', '');
    const res = await httpSafe('GET', GATEWAY + '/api/v1/Appointments/' + apptId);
    if (res.statusCode !== 200) return [{ json: { type: 'text', message: '❌ ' + extractErrMsg(res.body) } }];

    const a = res.body.data || res.body;
    const canCancel = ['PENDING','CONFIRMED'].includes(a.status);
    const info = '📋 THÔNG TIN LỊCH HẸN\n' +
                 '🕒 Thời gian: ' + fmtDateTime(a.scheduledAt) + '\n' +
                 '📊 Trạng thái: ' + fmtStatus(a.status) + '\n' +
                 '🆔 Mã: ' + a.appointmentId.slice(-8).toUpperCase();

    if (!canCancel) {
      return [{ json: { type: 'text', message: info + '\n\n(Lịch này không thể hủy)' } }];
    }

    const actions = [
      { id: 'cancel', label: '🚫 Hủy lịch này', payload: 'ACTION:CONFIRM_CANCEL:' + apptId },
      { id: 'back',   label: '↩️ Quay lại', payload: 'ACTION:VIEW_APPOINTMENTS' }
    ];
    return [{ json: { type: 'date_selection', message: info, data: actions } }];
  }

  // ── HỦY LỊCH: Xác nhận ──────────────────────────────
  if (cmd.startsWith('ACTION:CONFIRM_CANCEL:')) {
    const apptId = cmd.replace('ACTION:CONFIRM_CANCEL:', '');
    const actions = [
      { id: 'yes', label: '✅ Xác nhận hủy', payload: 'ACTION:EXECUTE_CANCEL:' + apptId },
      { id: 'no',  label: '❌ Không hủy',    payload: 'ACTION:VIEW_APPOINTMENTS' }
    ];
    return [{ json: { type: 'date_selection',
      message: '⚠️ Bạn có chắc muốn hủy lịch hẹn này?\nLý do hủy: Bệnh nhân yêu cầu hủy.',
      data: actions } }];
  }

  // ── HỦY LỊCH: Thực thi ──────────────────────────────
  if (cmd.startsWith('ACTION:EXECUTE_CANCEL:')) {
    const apptId = cmd.replace('ACTION:EXECUTE_CANCEL:', '');
    const res = await httpSafe('PUT', GATEWAY + '/api/v1/Appointments/' + apptId + '/cancel',
      { reason: 'Bệnh nhân yêu cầu hủy qua chatbot' });
    if (res.statusCode === 200 || res.statusCode === 201) {
      return [{ json: { type: 'text', message: '✅ Đã hủy lịch hẹn thành công.' } }];
    } else {
      return [{ json: { type: 'text', message: '❌ ' + extractErrMsg(res.body) } }];
    }
  }

  return [{ json: { type: 'text', message: 'Lệnh không nhận dạng được.' } }];
}

// ── 2. Classify with AI ──────────────────────────────────────
let intent = 'GREETING';
let greetingResponse = 'Xin chào! Tôi có thể giúp bạn đặt lịch khám, xem lịch hẹn hoặc tra cứu bệnh án.';
let extractedSpecialty = null;

try {
  const aiRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: { Authorization: 'Bearer ' + AI_KEY, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://dbh-ehr.local' },
    body: {
      model: 'openai/gpt-4o-mini',
      response_format: { type: 'json_object' },
      temperature: 0.1,
      messages: [
        { role: 'system', content:
            'Phan loai intent va trich xuat chuyen khoa. Examples:\n' +
            '- "Kham tim o dau": {"intent":"BOOK_APPOINTMENT","extractedSpecialty":"tim mach"}\n' +
            '- "Xem lich hen cua toi" hoac "lich kham cua toi" hoac "lich sắp tới": {"intent":"VIEW_APPOINTMENTS"}\n' +
            '- "Huy lich hen": {"intent":"VIEW_APPOINTMENTS"}\n' +
            '- "Cho xem ket qua xet nghiem": {"intent":"EHR_QUERY"}\n' +
            '- "Gio lam viec benh vien": {"intent":"POLICY_QUERY"}\n' +
            '- "Chao ban": {"intent":"GREETING","greetingResponse":"Xin chao!"}\n' +
            'Tra JSON: {"intent":"...","greetingResponse":"...","extractedSpecialty":"."}' },
        { role: 'user', content: rawMsg }
      ]
    },
    json: true
  });
  const aiText = aiRes?.choices?.[0]?.message?.content || '{}';
  let parsed = {};
  try { const m = aiText.match(/{[\s\S]*}/); if (m) parsed = JSON.parse(m[0]); } catch {}
  intent = parsed.intent || 'GREETING';
  greetingResponse = parsed.greetingResponse || 'Xin chào! Tôi có thể giúp gì cho bạn?';
  extractedSpecialty = parsed.extractedSpecialty || null;
} catch(e) {
  return [{ json: { type: 'text', message: 'Lỗi kết nối AI: ' + e.message } }];
}

// ── 3. Route by intent ────────────────────────────────
if (intent === 'GREETING') {
  return [{ json: { type: 'text', message: greetingResponse } }];
}

if (intent === 'POLICY_QUERY') {
  let userRole = 'patient';
  try { 
      const pd = await httpGet(GATEWAY + '/api/v1/auth/me'); 
      const rolesArray = pd.roles || pd.Roles || [];
      if (Array.isArray(rolesArray) && rolesArray.length > 0) {
          const adminStr = rolesArray.find(r => String(r).toLowerCase() === 'admin');
          userRole = adminStr ? 'admin' : String(rolesArray[0]).toLowerCase();
      }
  } catch(_) {}

  try {
    const ragRes = await this.helpers.httpRequest({
      method: 'POST', url: 'http://lightrag:9621/query',
      body: { query: rawMsg, mode: 'naive', namespace: userRole },
      json: true
    });
    const answer = ragRes.answer || ragRes.response || 'Không tìm thấy thông tin phù hợp.';
    return [{ json: { type: 'text', message: '📄 ' + answer } }];
  } catch(e) {
    return [{ json: { type: 'text', message: '❌ Lỗi hệ thống: ' + e.message } }];
  }
}

if (intent === 'VIEW_APPOINTMENTS') {
  let patientId = '';
  try {
    const pd = await httpGet(GATEWAY + '/api/v1/auth/me');
    const p = pd.profiles || pd.Profiles || {};
    const pt = p.Patient || p.patient || {};
    patientId = pt.patientId || pt.PatientId || '';
  } catch(e) { return [{ json: { type: 'text', message: '❌ Lỗi lấy hồ sơ: ' + e.message } }]; }

  if (!patientId) return [{ json: { type: 'text', message: '⚠️ Tài khoản chưa có hồ sơ Bệnh nhân.' } }];

  const res = await httpSafe('GET', GATEWAY + '/api/v1/Appointments?patientId=' + patientId + '&page=1&pageSize=8');
  if (res.statusCode !== 200) return [{ json: { type: 'text', message: '❌ ' + extractErrMsg(res.body) } }];

  const allAppts = res.body.data || res.body.Data || [];
  const active = allAppts.filter(a => !['CANCELLED','COMPLETED'].includes(a.status));

  if (active.length === 0) {
    return [{ json: { type: 'text', message: '📅 Bạn không có lịch hẹn nào đang hoạt động.\n\nGõ "đặt lịch khám" để đặt lịch mới.' } }];
  }

  const items = active.map(a => ({
    id: a.appointmentId,
    label: fmtDateTime(a.scheduledAt),
    sublabel: fmtStatus(a.status),
    payload: 'ACTION:APPT_DETAIL:' + a.appointmentId
  }));
  return [{ json: { type: 'date_selection', message: '📋 Lịch hẹn đang hoạt động (' + active.length + ' lịch) — Chọn để xem chi tiết / hủy:', data: items } }];
}

if (intent === 'BOOK_APPOINTMENT') {
  const spec = (extractedSpecialty || '').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '').replace(/đ/g, 'd').trim();
  try {
    const searchData = await httpPost(GATEWAY + '/api/v1/memberships/doctors/search',
      { specialty: spec || 'noi khoa', page: 1, pageSize: 10 });
    const rawData = searchData.data || searchData.Data || [];
    if (rawData.length === 0) return [{ json: { type: 'text', message: 'Không tìm thấy bác sĩ phù hợp.' } }];
    const docs = rawData.map(d => {
      const user = d.user || d.User || {};
      const up = user.userProfile || user.UserProfile || {};
      const p = up.profiles || up.Profiles || {};
      const doc = p.Doctor || p.doctor || {};
      return {
        doctorId: doc.doctorId || d.membershipId || '',
        name: user.fullName || up.fullName || 'Bác sĩ',
        specialty: d.specialty || spec,
        orgName: d.orgName || 'Bệnh viện',
        orgId: String(d.orgId || d.OrgId || '')
      };
    });
    return [{ json: { type: 'doctor_list', data: docs } }];
  } catch(e) {
    return [{ json: { type: 'text', message: 'Lỗi tìm bác sĩ: ' + e.message } }];
  }
}

if (intent === 'EHR_QUERY') {
  try {
    const profileData = await httpGet(GATEWAY + '/api/v1/auth/me');
    const p = profileData.profiles || profileData.Profiles || {};
    const patient = p.Patient || p.patient || {};
    const pId = patient.patientId || patient.PatientId || '';
    if (!pId) return [{ json: { type: 'text', message: 'Cần đăng nhập bệnh nhân.' } }];
    const ehrData = await httpGet(GATEWAY + '/api/v1/ehr/records/patient/' + pId);
    const records = ehrData.data || ehrData.Data || [];
    const count = Array.isArray(records) ? records.length : 0;
    const sum = count > 0 ? 'Tìm thấy ' + count + ' hồ sơ.' : 'Chưa có hồ sơ.';
    return [{ json: { type: 'card', data: { title: 'Hồ sơ bệnh án',
      subtitle: 'BN: ' + (patient.fullName || '?'), summary: sum,
      full_text: JSON.stringify(records, null, 2) } } }];
  } catch(e) {
    return [{ json: { type: 'text', message: 'Lỗi tra cứu: ' + e.message } }];
  }
}

return [{ json: { type: 'text', message: 'Tôi chưa hiểu yêu cầu này. Bạn có thể:\n• Đặt lịch khám\n• Xem lịch hẹn\n• Tra cứu bệnh án' } }];
